#include <iostream>
#include <string>
using namespace std;

class Solution {
public:
    string removeTrailingWhitespaces(string str) {
        while (str.size() > 0 && str[str.size()-1] == ' ' || str[str.size()-1] == '	') {
            str.pop_back();
        }
        return str;
    }
};

int main() {
    Solution solution;
    string str; cin >> str;
    str = solution.removeTrailingWhitespaces(str);
    cout << str << endl;
    return 0;
}
